blocks.code:
.three-col {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 24px;
}

.sidebar-layout {
  display: grid;
  grid-template-columns: 1fr 3fr; /* sidebar : main = 1 : 3 */
  gap: 24px;
}

.gallery {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
}

.page {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 64px 1fr 48px; /* header, content, footer */
  min-height: 100vh;
  gap: 16px;
}

/* Hero banner spans every column */
.hero {
  grid-column: 1 / -1;
}

/* Starts at column 2, spans two columns */
.wide-card {
  grid-column: 2 / span 2;
}

/* Grid for the overall page structure */
.page {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 64px 1fr;
  min-height: 100vh;
}

/* Flexbox inside the header cell */
.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
}

