exercise.solution:
.page {
  display: grid;
  grid-template-columns: 3fr 1fr;
  grid-template-rows: auto 1fr auto;
  gap: 24px;
  min-height: 100vh;
  padding: 24px;
}

.header {
  grid-column: 1 / -1;
  background: #dbeafe;
  padding: 16px;
}

.main {
  background: #dcfce7;
  padding: 16px;
}

.sidebar {
  background: #fef9c3;
  padding: 16px;
}

.footer {
  grid-column: 1 / -1;
  background: #dbeafe;
  padding: 16px;
}
